 1	import React, { FC } from 'react';
 2	
 3	import { V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import VncConsole from '@kubevirt-utils/components/Consoles/components/vnc-console/VncConsole';
 5	import { isHeadlessModeVMI } from '@kubevirt-utils/components/Consoles/utils/utils';
 6	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 7	import { vmiStatuses } from '@kubevirt-utils/resources/vmi';
 8	import { useAccessReview } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Bullseye, Button } from '@patternfly/react-core';
10	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
11	
12	import VirtualMachinesOverviewTabDetailsConsoleConnect from './VirtualMachinesOverviewTabDetailsConsoleConnect';
13	
14	type VirtualMachinesOverviewTabDetailsConsoleProps = {
15	  vmi: V1VirtualMachineInstance;
16	};
17	
18	const VirtualMachinesOverviewTabDetailsConsole: FC<
19	  VirtualMachinesOverviewTabDetailsConsoleProps
20	> = ({ vmi }) => {
21	  const { t } = useKubevirtTranslation();
22	
23	  const isHeadlessMode = isHeadlessModeVMI(vmi);
24	  const isVMRunning = vmi?.status?.phase === vmiStatuses.Running;
25	  const [canConnectConsole] = useAccessReview({
26	    group: 'subresources.kubevirt.io',
27	    name: vmi?.metadata?.name,
28	    namespace: vmi?.metadata?.namespace,
29	    resource: 'virtualmachineinstances/vnc',
30	    verb: 'get',
31	  });
32	  return (
33	    <Bullseye className="console-overview">
34	      <div className="link">
35	        <Button
36	          onClick={() =>
37	            window.open(
38	              `/k8s/ns/${vmi?.metadata?.namespace}/kubevirt.io~v1~VirtualMachine/${vmi?.metadata?.name}/console/standalone`,
39	            )
40	          }
41	          isDisabled={!isVMRunning || isHeadlessMode || !canConnectConsole}
42	          variant="link"
43	        >
44	          {t('Open web console')}
45	          <ExternalLinkAltIcon className="icon" />
46	        </Button>
47	      </div>
48	      {isVMRunning && !isHeadlessMode && canConnectConsole ? (
49	        <>
50	          <VncConsole
51	            CustomConnectComponent={VirtualMachinesOverviewTabDetailsConsoleConnect}
52	            viewOnly
53	            vmi={vmi}
54	          />
55	        </>
56	      ) : (
57	        <div className="pf-v5-c-console__vnc">
58	          <VirtualMachinesOverviewTabDetailsConsoleConnect
59	            isDisabled
60	            isHeadlessMode={isHeadlessMode}
61	          />
62	        </div>
63	      )}
64	    </Bullseye>
65	  );
66	};
67	
68	export default VirtualMachinesOverviewTabDetailsConsole;

